ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?title WHERE {
  ?movies a :Movies .
  ?movies p:Title ?title .
  ?movies p:Running_Time ?running_time_o .
  ?movies p:Extended_Version_Length ?extended_version_length_o .
}
ORDER BY ASC(?running_time_o) DESC(?extended_version_length_o) }
  component: { SELECT ?title WHERE {
  ?movies a :Movies .
  ?movies p:Title ?title .
  ?movies p:Running_Time ?running_time_o .
}
ORDER BY DESC(?running_time_o) }
  component_2: { SELECT ?title WHERE {
  ?movies a :Movies .
  ?movies p:Title ?title .
  ?movies p:Extended_Version_Length ?extended_version_length_o .
}
ORDER BY DESC(?extended_version_length_o) }
}

PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name WHERE {
  ?movies a :Movies .
  ?directors a :Directors .
  ?movies p:hasDirectors ?directors .
  ?directors p:name ?name .
  ?movies p:Extended_Version_Length ?extended_version_length_o .
}
ORDER BY DESC(?extended_version_length_o)
LIMIT 1 }
  component_2: { SELECT ?name WHERE {
  ?movies a :Movies .
  ?directors a :Directors .
  ?movies p:hasDirectors ?directors .
  ?directors p:name ?name .
  ?movies p:Running_Time ?running_time_o .
}
ORDER BY DESC(?running_time_o)
LIMIT 1 }
  full: { SELECT ?name WHERE {
  ?movies a :Movies .
  ?directors a :Directors .
  ?movies p:hasDirectors ?directors .
  ?directors p:name ?name .
  ?movies p:Running_Time ?running_time_o .
  ?movies p:Extended_Version_Length ?extended_version_length_o .
}
ORDER BY ASC(?running_time_o) DESC(?extended_version_length_o)
LIMIT 1 }
}
